const PROCESSING_FEE = 5;
const SWORD_BASE_PREMIUM = 100;
const AMULET_BASE_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const quotePremium = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const basePremium = items[0].type === "amulet" ? AMULET_BASE_PREMIUM : SWORD_BASE_PREMIUM;
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

